"""Generate the per-GPU bash run streams under run_streams/.

Re-run this if you change MODELS, DOMAINS, TASKS, VARIANTS, or the GPU layout.
"""

import os
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parents[2]))
from experiments.main_em_experiment import config as cfg

OUT = Path(cfg.EXP_ROOT) / "run_streams"
OUT.mkdir(parents=True, exist_ok=True)

_CONDA_LIB = os.path.dirname(cfg.PYTHON).replace("/bin", "/lib")
HEADER = f"""#!/usr/bin/env bash
# AUTO-GENERATED by experiments/main_em_experiment/run_streams_gen.py — do not hand-edit.
set -euo pipefail
cd "$(dirname "$0")/../../.."   # repo root: em_nlp_clean_repo
export PYTHONPATH="$PWD"
# Conda libstdc++ first — system GCC ships an older one that breaks unsloth's optree dep.
export LD_LIBRARY_PATH="{_CONDA_LIB}:${{LD_LIBRARY_PATH:-}}"
echo "[stream] $(date)  starting $(basename "$0")"
"""

PY = cfg.PYTHON  # /home/baskin/miniconda3/envs/llm_misalignment/bin/python


def _cell_cmd(model_key, d, t, variant, gpus, *, skip_narrow):
    cmd = [
        PY, "-m", "experiments.main_em_experiment.run_one",
        "--model_key", model_key,
        "--domain", d, "--task", t, "--variant", variant,
        "--gpus", gpus,
    ]
    if skip_narrow:
        cmd.append("--skip_narrow")
    return " ".join(cmd)


def main():
    cells = [(d, t) for d in cfg.DOMAINS for t in cfg.TASKS]

    # Llama: 1 GPU, sequential, strong-first then subtle (separate file per variant).
    for variant in cfg.VARIANTS:
        lines = [HEADER]
        lines.append(f'echo "=== llama3.1-8b  {variant}  PHASE 1 (general-eval) ==="')
        for d, t in cells:
            lines.append(_cell_cmd("llama3.1-8b", d, t, variant, "0", skip_narrow=True))
        lines.append(f'echo "=== llama3.1-8b  {variant}  PHASE 2 (narrow-eval) ==="')
        for d, t in cells:
            lines.append(_cell_cmd("llama3.1-8b", d, t, variant, "0", skip_narrow=False))
        lines.append('echo "[stream] DONE."')
        p = OUT / f"llama_{variant}.sh"
        p.write_text("\n".join(lines) + "\n")
        p.chmod(0o755)
        print(f"wrote {p}")

    # Qwen: 2 GPUs in parallel; alternate cells across GPUs (6 each).
    for variant in cfg.VARIANTS:
        for gpu_id, half in [("0", cells[0::2]), ("1", cells[1::2])]:
            lines = [HEADER]
            lines.append(f'echo "=== qwen2.5-14b  {variant}  GPU{gpu_id}  PHASE 1 (general-eval) ==="')
            for d, t in half:
                lines.append(_cell_cmd("qwen2.5-14b", d, t, variant, gpu_id, skip_narrow=True))
            lines.append(f'echo "=== qwen2.5-14b  {variant}  GPU{gpu_id}  PHASE 2 (narrow-eval) ==="')
            for d, t in half:
                lines.append(_cell_cmd("qwen2.5-14b", d, t, variant, gpu_id, skip_narrow=False))
            lines.append('echo "[stream] DONE."')
            p = OUT / f"qwen_{variant}_gpu{gpu_id}.sh"
            p.write_text("\n".join(lines) + "\n")
            p.chmod(0o755)
            print(f"wrote {p}")


if __name__ == "__main__":
    main()
